using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with a default resolver (handles any type) ---
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() – returns JsonTypeInfo<T> directly, no cast needed.
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() – probe without throwing.
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {info!.Type.Name}");
}

// --- Options with a restricted source-gen resolver (only knows about Person) ---
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = PersonContext.Default
};

// Person IS in the resolver → succeeds
if (restricted.TryGetTypeInfo<Person>(out var found))
{
    Console.WriteLine($"\nRestricted resolver: Person found → {found!.Type.Name}");
}

// int is NOT in the resolver → returns false instead of throwing
if (restricted.TryGetTypeInfo<int>(out _))
{
    Console.WriteLine("Restricted resolver: int found (unexpected)");
}
else
{
    Console.WriteLine("Restricted resolver: int NOT found — no exception thrown");
}

// --- Types ---
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;

